// Filtrar Tier B y seleccionar 3 marcas específicas
const rows = $input.all();
const tierBRows = rows.filter(r => r.json.tier === 'B');

// Seleccionar por rank exacto: 16, 33, 50
const selectedBrands = tierBRows.filter(r => 
  r.json.rank === '16' || r.json.rank === '33' || r.json.rank === '50'
);

// Mapear a estructura clara
const brands = selectedBrands.map(b => ({
  rank: parseInt(b.json.rank),
  brand_id: b.json.brand_id,
  category: b.json.category,
  tier: b.json.tier,
  gmv_cop_millions_12m: parseInt(b.json.gmv_cop_millions_12m),
  n_unique_clients_12m: parseInt(b.json.n_unique_clients_12m),
  gmv_90d_to_12m_ratio: parseFloat(b.json.gmv_90d_to_12m_ratio),
  recency_score: parseFloat(b.json.recency_score),
  fit_score: parseFloat(b.json.fit_score),
  momentum_score: parseFloat(b.json.momentum_score),
  final_score: parseFloat(b.json.final_score),
  why: b.json.why,
  routing: b.json.routing
}));

// Retornar los 3 items para procesamiento posterior
return brands.map(b => ({ json: b }));
